{
  "mcpServers": {
    "filesystem": {
      "command": "podman",
      "args": [
        "run",
        "--rm",
        "-i",
        "mcp/filesystem",
        "/home/haint/Projects",
        "/home/haint/Dropbox/Apps/Obsidian/Idea_Vault",
        "/home/haint/.agent_global"
      ],
      "disabled": true,
      "_comment": "Enable after building mcp/filesystem container. Provides file system access to Projects, Obsidian vault, and Agent Global Hub."
    },
    "obsidian": {
      "command": "npx",
      "args": [
        "-y",
        "@modelcontextprotocol/server-obsidian",
        "/home/haint/Dropbox/Apps/Obsidian/Idea_Vault"
      ],
      "disabled": true,
      "_comment": "Requires Node.js/npx. Provides semantic search and queries over Obsidian vault. Install: curl -fsSL https://deb.nodesource.com/setup_lts.x | sudo bash - && sudo dnf install -y nodejs"
    },
    "brave-search": {
      "command": "npx",
      "args": [
        "-y",
        "@modelcontextprotocol/server-brave-search"
      ],
      "env": {
        "BRAVE_API_KEY": "YOUR_BRAVE_API_KEY_HERE"
      },
      "disabled": true,
      "_comment": "Requires Node.js/npx and Brave Search API key. Get key from: https://brave.com/search/api/"
    },
    "github": {
      "command": "npx",
      "args": [
        "-y",
        "@modelcontextprotocol/server-github"
      ],
      "env": {
        "GITHUB_PERSONAL_ACCESS_TOKEN": "YOUR_GITHUB_TOKEN_HERE"
      },
      "disabled": true,
      "_comment": "Requires Node.js/npx and GitHub PAT. Provides access to GitHub repos, issues, PRs."
    }
  },
  "_readme": "See ~/.claude/MCP_SETUP.md for installation and configuration instructions"
}

